    const { test } = functions();
    const func = async () => {
      const data = await test();
      console.log(data);
      return data.data.id;
    }
    setUser(func());
  }, []);

  return (
    <div className={style.main}>
      <BrowserRouter>
        <Header/>
        <Routes>
          <Route index element={<Main/>}/>
          <Route path='/auth/signin' element={<Signin/>}/>
          <Route path='/auth/signup' element={<Signup/>}/>
        </Routes>
      </BrowserRouter>
    </div>
  );
}

export default App;
